sql:
SELECT domain, COUNT(sample_id) AS total_samples
FROM text_samples
GROUP BY domain;

SELECT AVG(variability) as AverageVariability
FROM text_samples
WHERE language = 'English' AND domain = 'Science';

SELECT sample_id
FROM text_samples
WHERE correct = 1;

SELECT sample_id 
FROM text_samples
WHERE variability > (SELECT AVG(variability) FROM text_samples);

SELECT source_name
FROM sources
WHERE source_id IN (SELECT source_id FROM text_samples);

SELECT domain 
FROM text_samples 
WHERE variability = (SELECT MAX(variability) FROM text_samples);

SELECT ts.sample_id, ts.text_content
FROM text_samples ts
INNER JOIN annotations a ON ts.sample_id = a.sample_id;

SELECT COUNT(*) AS Total_Corrected_Samples, AVG(ts.variability) AS Average_Variability
FROM text_samples ts
JOIN corrections c ON ts.sample_id = c.sample_id;

SELECT UPPER(source_name) AS SourceName, source_type AS SourceType
FROM sources
WHERE source_id BETWEEN 5 AND 10;

SELECT model_name, model_version, accuracy
FROM machine_learning_models
WHERE accuracy = (
    SELECT MAX(accuracy) 
    FROM machine_learning_models
);

SELECT model_id, COUNT(*) as Predictions_Count
FROM model_results
GROUP BY model_id;

SELECT COUNT(*)
FROM corrections
WHERE correction_type = 'specific_correction_type';

external_knowledge:
- The phrase "typical length" implies an average value; 
- "category" refers to the domain of the text samples;
- "texts that were corrected within a specific timeframe" means the corrections were made between 'start_date' and 'end_date'.

